+    overflow     = false;
+  }
+
+  void throw_on(action a) noexcept
+  {
+    should_throw = true;
+    throw_action = a;
+  }
+
+  void record(action a) noexcept
+  {
+    if (action_count < actions.size())
+    {
+      actions[action_count++] = a;
+    }
+    else
+    {
+      overflow = true;
+    }
+  }
+
+  void record_or_throw(action a)
+  {
+    this->record(a);
+    if (should_throw && throw_action == a)
+    {
+      should_throw = false;
+      throw std::runtime_error{"Injected fake_measure failure."};
+    }
+  }
+
+  void flush_device_l2() { this->record_or_throw(action::flush_device_l2); }
+  void sync_stream() { this->record_or_throw(action::sync_stream); }
+  int sync_stream_noexcept() noexcept
+  {
+    this->record(action::sync_stream_noexcept);
+    return 0;
+  }
+
+  void cpu_timer_start() noexcept { this->record(action::cpu_timer_start); }
+  void cpu_timer_stop() noexcept { this->record(action::cpu_timer_stop); }
+  void cpu_timer_stop_noexcept() noexcept { this->record(action::cpu_timer_stop_noexcept); }
+
+  void block_stream() { this->record_or_throw(action::block_stream); }
+  void unblock_stream() { this->record_or_throw(action::unblock_stream); }
+  void unblock_stream_noexcept() noexcept { this->record(action::unblock_stream_noexcept); }
+
+  void gpu_frequency_start() { this->record_or_throw(action::gpu_frequency_start); }
+  void gpu_frequency_stop() { this->record_or_throw(action::gpu_frequency_stop); }
+
+  void profiler_start() { this->record_or_throw(action::profiler_start); }
+  void profiler_stop() { this->record_or_throw(action::profiler_stop); }
+  int profiler_stop_noexcept() noexcept
+  {
+    this->record(action::profiler_stop_noexcept);
+    return 0;
+  }
+
+  void cuda_timer_start() { this->record_or_throw(action::cuda_timer_start); }
+  void cuda_timer_stop() { this->record_or_throw(action::cuda_timer_stop); }
+
+  std::array<action, 32> actions{};
+  std::size_t action_count{};
+  action throw_action{};
+  bool should_throw{false};
+  bool overflow{false};
+};
+
+template <typename Callable>
+void assert_throws(Callable &&callable)
+{
+  bool threw = false;
+  try
+  {
+    callable();
+  }
+  catch (const std::runtime_error &)
+  {
+    threw = true;
+  }
+  ASSERT(threw);
+}
+
+void assert_actions(const fake_measure &measure, std::initializer_list<action> expected)
+{
+  ASSERT(!measure.overflow);
+  ASSERT(measure.action_count == expected.size());
+
+  std::size_t index = 0;
+  for (const action expected_action : expected)
+  {
+    ASSERT(measure.actions[index] == expected_action);
+    ++index;
+  }
+}
+
+void test_stream_cleanup_guard_block_stream_throw()
+{
+  fake_measure measure;
+  measure.throw_on(action::block_stream);
+
+  assert_throws([&measure] {
+    nvbench::detail::stream_cleanup_guard<fake_measure> cleanup{measure};
+    cleanup.block_stream();
+  });
+
+  assert_actions(
+    measure,
+    {action::block_stream, action::unblock_stream_noexcept, action::sync_stream_noexcept});
+}
+
+void test_stream_cleanup_guard_unblock_then_throw()
+{
+  fake_measure measure;
+
+  assert_throws([&measure] {
+    nvbench::detail::stream_cleanup_guard<fake_measure> cleanup{measure};
+    cleanup.block_stream();
+    cleanup.unblock();
+    throw std::runtime_error{"Injected post-unblock failure."};
+  });
+
+  assert_actions(measure,
+                 {action::block_stream, action::unblock_stream, action::sync_stream_noexcept});
+}
+
+void test_kernel_launch_timer_block_stream_throw()
+{
+  fake_measure measure;
+  measure.throw_on(action::block_stream);
+
+  assert_throws([&measure] {
+    nvbench::detail::measure_cold_launch_timer_core<fake_measure> timer{
+      measure,
+      nvbench::detail::measure_cold_launch_timer_config{false, false, true}};
+    timer.start();
+  });
+
+  assert_actions(measure,
+                 {action::flush_device_l2,
+                  action::sync_stream,
+                  action::cpu_timer_start,
+                  action::block_stream,
+                  action::unblock_stream_noexcept,
+                  action::sync_stream_noexcept,
+                  action::cpu_timer_stop_noexcept});
+}
+
+void test_kernel_launch_timer_gpu_frequency_start_throw()
+{
+  fake_measure measure;
+  measure.throw_on(action::gpu_frequency_start);
+
+  assert_throws([&measure] {
+    nvbench::detail::measure_cold_launch_timer_core<fake_measure> timer{
+      measure,
+      nvbench::detail::measure_cold_launch_timer_config{false, false, true}};
+    timer.start();
+  });
+
+  assert_actions(measure,
+                 {action::flush_device_l2,
+                  action::sync_stream,
+                  action::cpu_timer_start,
+                  action::block_stream,
+                  action::gpu_frequency_start,
+                  action::unblock_stream_noexcept,
+                  action::sync_stream_noexcept,
+                  action::cpu_timer_stop_noexcept});
+}
+
+void test_kernel_launch_timer_gpu_frequency_stop_throw()
+{
+  fake_measure measure;
+  nvbench::detail::measure_cold_launch_timer_core<fake_measure> timer{
+    measure,
+    nvbench::detail::measure_cold_launch_timer_config{false, false, true}};
+
+  timer.start();
+  measure.clear_actions();
+  measure.throw_on(action::gpu_frequency_stop);
+
+  assert_throws([&timer] { timer.stop(); });
+
+  assert_actions(measure,
+                 {action::cuda_timer_stop,
+                  action::gpu_frequency_stop,
+                  action::unblock_stream_noexcept,
+                  action::sync_stream_noexcept,
+                  action::cpu_timer_stop_noexcept});
+}
+
+} // namespace
+
+int main()
+try
+{
+  test_stream_cleanup_guard_block_stream_throw();
+  test_stream_cleanup_guard_unblock_then_throw();
+  test_kernel_launch_timer_block_stream_throw();
+  test_kernel_launch_timer_gpu_frequency_start_throw();
+  test_kernel_launch_timer_gpu_frequency_stop_throw();
+
+  return 0;
+}
+catch (std::exception &e)
+{
+  fmt::print("{}\n", e.what());
+  return 1;
+}
diff --git a/testing/exception_safety.cu b/testing/exception_safety.cu
new file mode 100644
index 0000000..f5f0c38
--- /dev/null
+++ b/testing/exception_safety.cu
@@ -0,0 +1,203 @@
+// SPDX-FileCopyrightText: Copyright (c) 2026, NVIDIA CORPORATION.
+// SPDX-License-Identifier: Apache-2.0 WITH LLVM-exception
+
+#include <nvbench/benchmark.cuh>
+#include <nvbench/cuda_call.cuh>
+#include <nvbench/exec_tag.cuh>
+#include <nvbench/launch.cuh>
+#include <nvbench/runner.cuh>
+#include <nvbench/state.cuh>
+#include <nvbench/type_list.cuh>
+#include <nvbench/types.cuh>
+
+#include <cuda_runtime.h>
+
+#include <fmt/format.h>
+
+#include <chrono>
+#include <stdexcept>
+#include <string>
+
+#include "test_asserts.cuh"
+
+namespace
+{
+
+__global__ void spin_kernel(nvbench::uint64_t target_cycles)
+{
+  const auto start = static_cast<nvbench::uint64_t>(clock64());
+  while (static_cast<nvbench::uint64_t>(clock64()) - start < target_cycles)
+  {
+  }
+}
+
+constexpr nvbench::uint64_t spin_cycles = 100000;
+
+enum class measurement_kind
+{
+  cold,
+  hot,
+};
+
+enum class exception_kind
+{
+  runtime_error,
+  stop_runner_loop,
+};
+
+struct test_control
+{
+  measurement_kind measurement{measurement_kind::cold};
+  exception_kind exception{exception_kind::runtime_error};
+  int generator_calls{0};
+  int launcher_calls{0};
+};
+
+void synchronize_with_timeout_guard()
+{
+  const auto start = std::chrono::steady_clock::now();
+  NVBENCH_CUDA_CALL(cudaDeviceSynchronize());
+  const auto elapsed = std::chrono::steady_clock::now() - start;
+
+  ASSERT_MSG(elapsed < std::chrono::seconds{5},
+             "cudaDeviceSynchronize took {} ms; stream cleanup may have leaked blocked work",
+             std::chrono::duration_cast<std::chrono::milliseconds>(elapsed).count());
+}
+
+void throw_requested_exception(exception_kind exception)
+{
+  if (exception == exception_kind::stop_runner_loop)
+  {
+    throw nvbench::stop_runner_loop{"requested stop from exception-safety test"};
+  }
+
+  throw std::runtime_error{"requested throw from exception-safety test"};
+}
+
+void configure_state(nvbench::state &state)
+{
+  state.set_min_samples(1);
+  state.set_timeout(0.01);
+
+  // Keep this below the CTest timeout. If cleanup fails to unblock the
+  // blocking kernel, the device-side timeout lets the elapsed-time assertion
+  // report the leak before CTest has to kill the process.
+  state.set_blocking_kernel_timeout(10.0);
+}
+
+void run_throwing_measurement(nvbench::state &state, test_control &control)
+{
+  configure_state(state);
+
+  auto launcher = [&control](nvbench::launch &launch) {
+    ++control.launcher_calls;
+    spin_kernel<<<1, 1, 0, launch.get_stream()>>>(spin_cycles);
+
+    // Let the warmup complete. The next launcher call happens under the cold
+    // or hot measurement cleanup path that this test is exercising.
+    if (control.launcher_calls > 1)
+    {
+      throw_requested_exception(control.exception);
+    }
+  };
+
+  if (control.measurement == measurement_kind::hot)
+  {
+    state.exec(nvbench::exec_tag::impl::hot, launcher);
+  }
+  else
+  {
+    state.exec(nvbench::exec_tag::impl::cold, launcher);
+  }
+}
+
+struct throwing_generator
+{
+  test_control *control{};
+
+  void operator()(nvbench::state &state, nvbench::type_list<>) const
+  {
+    ++control->generator_calls;
+    run_throwing_measurement(state, *control);
+  }
+};
+
+using benchmark_type = nvbench::benchmark<throwing_generator>;
+
+void run_benchmark(test_control &control, bool add_axis = false)
+{
+  benchmark_type bench{throwing_generator{&control}};
+  bench.add_device(0);
+  bench.set_min_samples(1);
+  bench.set_timeout(0.01);
+  bench.set_criterion_param_float64("min-time", 1e-6);
+  if (add_axis)
+  {
+    bench.add_int64_axis("Case", {0, 1, 2});
+  }
+
+  bench.run();
+
+  synchronize_with_timeout_guard();
+
+  const auto &states = bench.get_states();
+  ASSERT(!states.empty());
+  for (const auto &state : states)
+  {
+    ASSERT(state.is_skipped());
+    ASSERT(state.get_skip_reason().find("requested") != std::string::npos);
+  }
+}
+
+void test_cold_runtime_error_cleanup()
+{
+  test_control control;
+  control.measurement = measurement_kind::cold;
+  control.exception   = exception_kind::runtime_error;
+
+  run_benchmark(control);
+
+  ASSERT(control.generator_calls == 1);
+  ASSERT(control.launcher_calls == 2);
+}
+
+void test_hot_runtime_error_cleanup()
+{
+  test_control control;
+  control.measurement = measurement_kind::hot;
+  control.exception   = exception_kind::runtime_error;
+
+  run_benchmark(control);
+
+  ASSERT(control.generator_calls == 1);
+  ASSERT(control.launcher_calls == 2);
+}
+
+void test_stop_runner_loop_cleanup_and_skip_remaining()
+{
+  test_control control;
+  control.measurement = measurement_kind::cold;
+  control.exception   = exception_kind::stop_runner_loop;
+
+  run_benchmark(control, true);
+
+  ASSERT(control.generator_calls == 1);
+  ASSERT(control.launcher_calls == 2);
+}
+
+} // namespace
+
+int main()
+try
+{
+  test_cold_runtime_error_cleanup();
+  test_hot_runtime_error_cleanup();
+  test_stop_runner_loop_cleanup_and_skip_remaining();
+
+  return 0;
+}
+catch (std::exception &e)
+{
+  fmt::print("{}\n", e.what());
+  return 1;
+}

commit 9ea77bccaabf6b2e7fbe468d8c852f6258e8bc02
Author: Oleksandr Pavlyk <21087696+oleksandr-pavlyk@users.noreply.github.com>
Date:   Tue May 12 14:30:08 2026 -0500

    Implement CLI option to control warmups for cold measurements (#339)

    * Implement warmup-runs count, supported as CLI

    CLI option --warmup-runs implemented and documented.

    The warm-up counts is enforced to always be positive.
    This is necessary to ensure that JIT-ting has occurred,
    and use of blocking kernel would not result in time-outs.

    Test is option parser is added.

    * Ensure that measure_cold::run_warmup instantiates blocking kernel

    Because warm-up runs are executed without use of blocking kernel,
    the blocking kernel was not jitted until actual measurements were
    collected. The module loading cost incurred during the first run
    shows as elevated CPU time noise value for the first measurement
    as noted in https://github.com/NVIDIA/nvbench/pull/339

    This PR adds `this->block_stream(); this->unblock_stream();` prior
    to executing warm-up loop with use of blocking kernel disabled.

    This ensures that blocking kernel is instantiated during the warm-up,
    but it no other kernel is launched between its launch and stream sync
    thus avoiding deadlocking.

    * Rename --warmup-runs to --cold-warmup-runs, add --cold-max-warmup-walltime

    Since configurable number of warmups only applies to measure_cold.cuh
    rename the CLI option to reflect that.

    Also add --cold-max-warmup-walltime (defaults to -1, i.e. disabled).
    If enabled, exits warmup loop before request count is reached if
    the wall-time expanded executign warmups exceeds this max-warmup-walltime
    value.
