+bool is_little_endian()
+{
+#if NVBENCH_CPP_DIALECT >= 2020
+  return std::endian::native == std::endian::little;
+#else
+  const nvbench::uint32_t word = {0xBadDecaf};
+  nvbench::uint8_t bytes[4];
+  std::memcpy(bytes, &word, 4);
+  return bytes[0] == 0xaf;
+#endif
+}
